SELECT el.id, el.engineer_id, el.start_date, el.end_date, el.leave_type,
       el.reason, el.status, el.create_time,
       e.name AS engineer_name
FROM engineer_leave el
LEFT JOIN engineer e ON e.id = el.engineer_id AND e.deleted = 0

    el.deleted = 0

        AND el.engineer_id = #{query.engineerId}


        AND el.leave_type = #{query.leaveType}


        AND el.status = #{query.status}


        AND el.end_date >= #{query.startDate}


        AND el.start_date <= #{query.endDate}


ORDER BY el.start_date DESC, el.id DESC

SELECT id, engineer_id, start_date, end_date, leave_type, reason, status,
       create_by, create_time, update_by, update_time, deleted
FROM engineer_leave
WHERE deleted = 0
  AND status = 'APPROVED'

      AND engineer_id = #{engineerId}

  AND end_date >= #{startDate}
  AND start_date <= #{endDate}
ORDER BY start_date ASC
